      a2i = _mm512_add_pd(v7_im, v8_im);
      b1r = _mm512_sub_pd(v6_re, v9_re);
      b1i = _mm512_sub_pd(v6_im, v9_im);
      b2r = _mm512_sub_pd(v7_re, v8_re);
      b2i = _mm512_sub_pd(v7_im, v8_im);
