      t1i = _mm512_add_pd(a1i, a2i);
      t2r = _mm512_sub_pd(a1r, a2r);
      t2i = _mm512_sub_pd(a1i, a2i);
      x0sr = v5_re;
      x0si = v5_im;
      v5_re = _mm512_add_pd(x0sr, t1r);
      v5_im = _mm512_add_pd(x0si, t1i);
      m1r = _mm512_mul_pd(t1r, cW5a);
      m1i = _mm512_mul_pd(t1i, cW5a);
      m2r = _mm512_mul_pd(t2r, cW5b);
      m2i = _mm512_mul_pd(t2i, cW5b);
      p1r = _mm512_mul_pd(cW5s2, _mm512_add_pd(b1r, b2r));
      p1i = _mm512_mul_pd(cW5s2, _mm512_add_pd(b1i, b2i));
