      p2i = _mm512_mul_pd(cW5d, b1i);
      p3r = _mm512_mul_pd(cW5p, b2r);
      p3i = _mm512_mul_pd(cW5p, b2i);
      q1r = _mm512_add_pd(p1r, p2r);
      q1i = _mm512_add_pd(p1i, p2i);
      q2r = _mm512_sub_pd(p1r, p3r);
      q2i = _mm512_sub_pd(p1i, p3i);
      w1r = _mm512_add_pd(x0sr, m1r);
      w1i = _mm512_add_pd(x0si, m1i);
      w2r = _mm512_add_pd(w1r, m2r);
      w2i = _mm512_add_pd(w1i, m2i);
      w3r = _mm512_sub_pd(w1r, m2r);
      w3i = _mm512_sub_pd(w1i, m2i);
      v6_re = _mm512_add_pd(w2r, q1i);
      v6_im = _mm512_sub_pd(w2i, q1r);
      v9_re = _mm512_sub_pd(w2r, q1i);
      v9_im = _mm512_add_pd(w2i, q1r);
      v7_re = _mm512_add_pd(w3r, q2i);
      v7_im = _mm512_sub_pd(w3i, q2r);
      v8_re = _mm512_sub_pd(w3r, q2i);
      v8_im = _mm512_add_pd(w3i, q2r);
